import React from "react";
import { Box, Paper, Stack, Typography } from "@mui/material";
import { BusinessResult } from "@/types/business.types";
import StorefrontIcon from '@mui/icons-material/Storefront';
import WhatsAppIcon from '@mui/icons-material/WhatsApp';
import EmailIcon from '@mui/icons-material/Email';
import PhoneIcon from '@mui/icons-material/Phone';
import PlaceIcon from '@mui/icons-material/Place';
import LanguageIcon from '@mui/icons-material/Language';
import PersonIcon from '@mui/icons-material/Person';
import InfoIcon from '@mui/icons-material/Info';
import LocalOfferIcon from '@mui/icons-material/LocalOffer';
import { ProfileInfoDialog } from '@/components/ProfileInfoDialog';
import { IconActionButton } from '@/components/ui/IconActionButton';

interface BusinessCardProps extends BusinessResult {
  isAdmin?: boolean;
  extraActions?: React.ReactNode;
}

const InfoRow: React.FC<{ icon: React.ReactNode; children: React.ReactNode }> = ({ icon, children }) => (
  <Box sx={{ display: 'flex', alignItems: 'flex-start', gap: 0.75, minWidth: 0, py: 0.2 }}>
    <Box sx={{ color: 'action.active', display: 'flex', flexShrink: 0, mt: '2px' }}>{icon}</Box>
    <Typography variant="body2" sx={{ fontSize: '0.8125rem', wordBreak: 'break-word' }}>
      {children}
    </Typography>
  </Box>
);

export const BusinessCard = React.memo((props: BusinessCardProps) => {
    const { isAdmin, extraActions, ...business } = props;
    const [profileOpen, setProfileOpen] = React.useState(false);
    const hasAddress = !!business.address;
    const hasDetails = !!business.details;
    const hasEmail = !!business.email;
    const hasWebsite = !!business.website;
    const hasMapLink = !!business.mapLink;
    const hasOffer = !!business.offer;

    return (
        <Paper
            elevation={1}
            sx={{
                p: 1.5,
                mb: 1,
                borderRadius: 2,
                borderLeft: 3,
                borderColor: 'secondary.light',
                transition: 'box-shadow 0.2s ease',
                overflow: 'hidden',
                '&:hover': { boxShadow: 4 },
            }}
        >
            {/* Header: Name + Category + Location */}
            <Stack direction="row" spacing={0.75} sx={{ alignItems: 'center', mb: 0.25, minWidth: 0 }}>
                <StorefrontIcon sx={{ fontSize: '1.1rem', color: 'secondary.main', flexShrink: 0 }} />
                <Typography variant="subtitle2" sx={{ fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {business.name}
                </Typography>
            </Stack>
            <Box sx={{ ml: 0.25, mb: 0.5, display: 'flex', alignItems: 'center', gap: 0.5, flexWrap: 'wrap' }}>
                {business.category && (
                    <Box sx={{ display: 'inline-flex', alignItems: 'center', gap: 0.25 }}>
                        <LocalOfferIcon sx={{ fontSize: '0.85rem', color: 'text.secondary' }} />
                        <Typography variant="caption" color="text.secondary">{business.category}</Typography>
                    </Box>
                )}
                {hasAddress && (
                    <Box sx={{ display: 'inline-flex', alignItems: 'center', gap: 0.25 }}>
                        <Typography variant="caption" color="text.secondary">·</Typography>
                        <PlaceIcon sx={{ fontSize: '0.85rem', color: 'text.secondary' }} />
                        <Typography variant="caption" color="text.secondary">{business.address}{business.pinCode ? `, ${business.pinCode}` : ''}</Typography>
                    </Box>
                )}
            </Box>

            {/* Info — single column */}
            <Stack spacing={0.25} sx={{ ml: 0.25 }}>
                {hasDetails && (
                    <InfoRow icon={<InfoIcon sx={{ fontSize: '0.95rem' }} />}>
                        {business.details}
                    </InfoRow>
                )}
                {hasEmail && (
                    <InfoRow icon={<EmailIcon sx={{ fontSize: '0.95rem' }} />}>
                        {business.email}
                    </InfoRow>
                )}
                {hasOffer && (
                    <InfoRow icon={<LocalOfferIcon sx={{ fontSize: '0.95rem' }} />}>
                        {business.offer}
                    </InfoRow>
                )}
                {business.createdByName && (
                    <InfoRow icon={<PersonIcon sx={{ fontSize: '0.95rem' }} />}>
                        <Box
                            component="span"
                            onClick={() => setProfileOpen(true)}
                            sx={{ cursor: 'pointer', '&:hover': { textDecoration: 'underline' }, color: 'primary.main' }}
                        >
                            {business.createdByName}
                        </Box>
                    </InfoRow>
                )}
            </Stack>

            <InfoRow icon={<PhoneIcon sx={{ fontSize: '0.95rem' }} />}>
                {business.phone}
            </InfoRow>

            {/* Action icons row */}
            <Box sx={{ display: 'flex', alignItems: 'center', mt: 1, width: '100%' }}>
                <Stack direction="row" spacing={1.5}>
                    <IconActionButton tone="primary" aria-label="call" href={`tel:${business.phone}`}>
                        <PhoneIcon sx={{ fontSize: '1rem' }} />
                    </IconActionButton>
                    <IconActionButton tone="whatsapp" aria-label="whatsapp" href={`https://wa.me/91${business.phone}`} target="_blank" rel="noopener noreferrer">
                        <WhatsAppIcon sx={{ fontSize: '1rem' }} />
                    </IconActionButton>
                    {hasEmail && (
                        <IconActionButton tone="primary" aria-label="email" href={`mailto:${business.email ?? ''}`}>
                            <EmailIcon sx={{ fontSize: '1rem' }} />
                        </IconActionButton>
                    )}
                    {hasMapLink && (
                        <IconActionButton tone="primary" aria-label="map" href={business.mapLink ?? ''} target="_blank" rel="noopener noreferrer">
                            <PlaceIcon sx={{ fontSize: '1rem' }} />
                        </IconActionButton>
                    )}
                    {hasWebsite && (
                        <IconActionButton tone="primary" aria-label="website" href={business.website ?? ''} target="_blank" rel="noopener noreferrer">
                            <LanguageIcon sx={{ fontSize: '1rem' }} />
                        </IconActionButton>
                    )}
                </Stack>
                {extraActions && (
                    <Stack direction="row" spacing={1.5} sx={{ ml: 'auto' }}>
                        {extraActions}
                    </Stack>
                )}
            </Box>

            <ProfileInfoDialog
                open={profileOpen}
                profileId={business.createdBy ?? ''}
                mode={isAdmin ? 'admin' : 'public'}
                onClose={() => setProfileOpen(false)}
            />
        </Paper>
    );
});
BusinessCard.displayName = 'BusinessCard';
