/**
 * IconActionButton — standardized circular action button used by cards.
 *
 * Replaces ad-hoc IconButton usages with `sx={{ color: '#fff', bgcolor: 'X.main', '&:hover': { bgcolor: 'X.dark' } }}`
 * scattered across BusinessCard, EventCard, AttendeeRow, BusinessDisplay, etc.
 */
import * as React from 'react';
import { IconButton, IconButtonProps } from '@mui/material';

export type IconActionTone = 'primary' | 'secondary' | 'error' | 'success' | 'warning' | 'info' | 'whatsapp';

const TONE_STYLES: Record<IconActionTone, { bg: string; bgHover: string; color: string }> = {
    primary:   { bg: 'primary.main',   bgHover: 'primary.dark',   color: 'common.white' },
    secondary: { bg: 'secondary.main', bgHover: 'secondary.dark', color: 'common.white' },
    error:     { bg: 'error.main',     bgHover: 'error.dark',     color: 'common.white' },
    success:   { bg: 'success.main',   bgHover: 'success.dark',   color: 'common.white' },
    warning:   { bg: 'warning.main',   bgHover: 'warning.dark',   color: 'common.white' },
    info:      { bg: 'info.main',      bgHover: 'info.dark',      color: 'common.white' },
    whatsapp:  { bg: '#25D366',        bgHover: '#1ebe57',        color: 'common.white' },
};

export interface IconActionButtonProps extends Omit<IconButtonProps, 'color'> {
    tone?: IconActionTone;
    /** Render as an <a> when provided. */
    href?: string;
    target?: string;
    rel?: string;
}

export const IconActionButton = React.forwardRef<HTMLButtonElement, IconActionButtonProps>(
    ({ tone = 'primary', size = 'small', sx, children, href, ...rest }, ref) => {
        const { bg, bgHover, color } = TONE_STYLES[tone];
        const anchorProps = href ? ({ component: 'a', href } as const) : {};
        return (
            <IconButton
                ref={ref}
                size={size}
                {...anchorProps}
                sx={[
                    { color, bgcolor: bg, '&:hover': { bgcolor: bgHover } },
                    ...(Array.isArray(sx) ? sx : [sx]),
                ]}
                {...rest}
            >
                {children}
            </IconButton>
        );
    }
);

IconActionButton.displayName = 'IconActionButton';

export default IconActionButton;
